import React, { useState, useEffect } from 'react';
import api from '../services/api';

function BalanceView({ refreshTrigger, onSettlementMade }) {
  const [balances, setBalances] = useState([]);
  const [suggestedPayments, setSuggestedPayments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showSettlement, setShowSettlement] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState(null);
  const [settlementDate, setSettlementDate] = useState(new Date().toISOString().split('T')[0]);
  const [processingPayment, setProcessingPayment] = useState(false);
  const [processedPayments, setProcessedPayments] = useState(new Set());

  useEffect(() => {
    loadBalances();
  }, [refreshTrigger]);

  const loadBalances = async () => {
    setLoading(true);
    try {
      const data = await api.getBalances();
      setBalances(data.balances);
      setSuggestedPayments(data.suggestedPayments);
      // Clear processed payments when balances refresh
      setProcessedPayments(new Set());
    } catch (error) {
      console.error('Error loading balances:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSettlePayment = async (payment) => {
    // Prevent duplicate submissions
    const paymentKey = `${payment.from}-${payment.to}-${payment.amount}`;
    if (processedPayments.has(paymentKey)) {
      alert('This payment is already being processed!');
      return;
    }
    
    if (processingPayment) {
      alert('Please wait, processing payment...');
      return;
    }

    setProcessingPayment(true);
    setProcessedPayments(prev => new Set(prev).add(paymentKey));

    try {
      await api.addSettlement({
        from_friend_id: payment.from,
        to_friend_id: payment.to,
        amount: payment.amount,
        date: settlementDate
      });
      alert(`Settlement recorded: ${payment.from_name} pays ${payment.to_name} $${payment.amount.toFixed(2)}`);
      setShowSettlement(false);
      setSelectedPayment(null);
      onSettlementMade();
      await loadBalances(); // Reload balances immediately
    } catch (error) {
      console.error('Error recording settlement:', error);
      alert(error.response?.data?.error || 'Error recording settlement');
      // Remove from processed set on error so user can retry
      setProcessedPayments(prev => {
        const newSet = new Set(prev);
        newSet.delete(paymentKey);
        return newSet;
      });
    } finally {
      setProcessingPayment(false);
    }
  };

  if (loading) {
    return <div>Loading balances...</div>;
  }

  return (
    <div>
      <h2>Current Balances</h2>
      
      <div className="card">
        <h3>Net Balances</h3>
        <p style={{ fontSize: '0.9em', color: '#666', marginBottom: '15px' }}>
          Positive = owed to you | Negative = you owe
        </p>
        {balances.map(person => (
          <div key={person.id} style={{ 
            display: 'flex', 
            justifyContent: 'space-between',
            padding: '10px',
            borderBottom: '1px solid #e0e0e0'
          }}>
            <span>{person.name}</span>
            <span className={
              person.balance > 0 ? 'balance-positive' : 
              person.balance < 0 ? 'balance-negative' : 'balance-neutral'
            }>
              ${Math.abs(person.balance).toFixed(2)} {person.balance > 0 ? 'owed to you' : person.balance < 0 ? 'you owe' : ''}
            </span>
          </div>
        ))}
      </div>

      {suggestedPayments.length > 0 && (
        <div className="card">
          <h3>Suggested Payments to Settle Up</h3>
          {suggestedPayments.map((payment, index) => (
            <div key={index} style={{
              padding: '15px',
              margin: '10px 0',
              background: '#e8f4f8',
              borderRadius: '8px'
            }}>
              <p style={{ marginBottom: '10px' }}>
                <strong>{payment.from_name}</strong> should pay <strong>{payment.to_name}</strong> 
                <span className="balance-positive"> ${payment.amount.toFixed(2)}</span>
              </p>
              <button 
                onClick={() => {
                  setSelectedPayment(payment);
                  setShowSettlement(true);
                }}
                style={{ background: '#10b981' }}
                disabled={processingPayment}
              >
                Mark as Paid
              </button>
            </div>
          ))}
        </div>
      )}

      {showSettlement && selectedPayment && (
        <div className="card" style={{ background: '#fff3cd' }}>
          <h3>Record Payment</h3>
          <p><strong>{selectedPayment.from_name}</strong> pays <strong>{selectedPayment.to_name}</strong> ${selectedPayment.amount.toFixed(2)}</p>
          <div className="form-group">
            <label>Date:</label>
            <input
              type="date"
              value={settlementDate}
              onChange={(e) => setSettlementDate(e.target.value)}
            />
          </div>
          <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
            <button 
              onClick={() => handleSettlePayment(selectedPayment)}
              disabled={processingPayment}
            >
              {processingPayment ? 'Processing...' : 'Confirm Payment'}
            </button>
            <button 
              onClick={() => {
                setShowSettlement(false);
                setSelectedPayment(null);
              }} 
              style={{ background: '#6c757d' }}
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default BalanceView;
